import React from 'react'
import Vittoria from './Vittoria';
import Sconfitta from './Sconfitta';

function FineGame({fineGame}){
  if (fineGame === "vittoria") return <Vittoria/>
  if (fineGame === "sconfitta") return <Vittoria/>
  return (
    <div className={`fineGame ${fineGame} ${fineGame && "visible"}`}>
      <div className='circle center'></div>

    </div>
  )
}

export default FineGame;
